INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('38dfc7b0-7782-4981-ad2e-a001a47660eb', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'Por que a privacidade de dados é fundamental ao utilizar ferramentas de IA que processam informações?', '["A privacidade de dados n\u00e3o \u00e9 relevante para a IA.", "Para proteger informa\u00e7\u00f5es confidenciais de funcion\u00e1rios e clientes contra vazamentos e uso indevido.", "Para aumentar o volume de dados coletados.", "Para garantir que os dados sejam compartilhados livremente com terceiros."]', 1, 'Proteger a privacidade de dados é essencial para garantir a confidencialidade e a conformidade legal, evitando vazamentos e uso indevido de informações sensíveis.', '2026-03-05T20:18:42.1253+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('52bd194c-b1d9-4204-8aef-0f213fd0fe69', 'fe23fcf4-3489-40eb-a133-31aea69cbcb1', 'O que significa ''viés algorítmico'' em ferramentas de IA?', '["O algoritmo \u00e9 perfeitamente imparcial e nunca falha.", "O algoritmo reflete e amplifica preconceitos presentes nos dados de treinamento.", "O algoritmo \u00e9 projetado para ser menos preciso.", "O algoritmo s\u00f3 funciona com dados de alta qualidade."]', 1, 'Viés algorítmico ocorre quando um algoritmo reflete ou amplifica preconceitos existentes nos dados com os quais foi treinado, levando a resultados discriminatórios.', '2026-03-05T20:18:42.1253+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('30f3b1ea-7703-42ea-92ca-97c7164a431d', '6652a578-9328-4d81-a51a-5cef002b123f', 'Ao selecionar uma ferramenta de IA para sua empresa, qual critério é mais importante considerar?', '["O pre\u00e7o mais baixo dispon\u00edvel no mercado.", "O alinhamento com as necessidades espec\u00edficas do neg\u00f3cio e a facilidade de uso.", "A popularidade da ferramenta sem verificar sua funcionalidade.", "A capacidade de realizar tarefas n\u00e3o relacionadas ao objetivo principal."]', 1, 'É crucial selecionar ferramentas de IA que se alinhem com as necessidades específicas do negócio e que ofereçam uma interface intuitiva para facilitar a adoção e o uso.', '2026-03-05T20:19:09.42259+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('46fb5832-607f-4350-9b3e-c97db6d97cf5', '6652a578-9328-4d81-a51a-5cef002b123f', 'Qual estratégia pode auxiliar na adoção de IA em uma equipe de trabalho?', '["Impor o uso da IA sem treinamento pr\u00e9vio.", "Oferecer treinamento adequado e demonstrar os benef\u00edcios pr\u00e1ticos da ferramenta.", "Ignorar as d\u00favidas e preocupa\u00e7\u00f5es dos membros da equipe.", "Iniciar a implementa\u00e7\u00e3o com as ferramentas mais complexas e menos intuitivas."]', 1, 'Oferecer treinamento abrangente e demonstrar os benefícios tangíveis da IA são estratégias eficazes para promover a adoção e o engajamento da equipe.', '2026-03-05T20:19:09.42259+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('d48c7bb7-ed65-433a-9f59-04b5675b2f65', '6652a578-9328-4d81-a51a-5cef002b123f', 'Quais são as tendências emergentes na aplicação da IA para aumentar a produtividade no trabalho no futuro?', '["Desuso generalizado de ferramentas de IA.", "IA conversacional mais avan\u00e7ada, personaliza\u00e7\u00e3o hiper-inteligente e automa\u00e7\u00e3o colaborativa.", "Foco exclusivo em tarefas manuais e repetitivas.", "Regress\u00e3o para m\u00e9todos de trabalho puramente manuais."]', 1, 'Tendências futuras incluem IA conversacional mais sofisticada, personalização avançada e a automação colaborativa entre humanos e IA.', '2026-03-05T20:19:09.42259+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c8a798c6-8589-4826-af1f-f88feaad85c2', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Qual é a função principal de uma variável em programação?', '["Executar comandos espec\u00edficos.", "Armazenar e referenciar dados em mem\u00f3ria.", "Exibir mensagens na tela do usu\u00e1rio.", "Criar novas fun\u00e7\u00f5es no programa."]', 1, 'Variáveis são como caixas nomeadas em que podemos guardar valores que podem mudar durante a execução do programa.', '2026-03-11T17:37:19.163889+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('f4b83c7f-6e10-494f-84ee-54617ae1373e', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Qual tipo de dado é mais apropriado para armazenar o número de alunos em uma turma?', '["Ponto flutuante (float/double)", "Booleano (boolean)", "String", "Inteiro (integer)"]', 3, 'Um número inteiro é o tipo de dado mais adequado, pois a quantidade de alunos deve ser um número completo e sem frações.', '2026-03-11T17:37:19.163889+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('fec1d8ac-9743-4711-a3a7-72371f3facaa', 'ad899c16-05d0-42b1-956c-90a067c54081', 'Qual operador é utilizado para verificar se duas variáveis possuem valores iguais?', '["=", "==", "!=", ">"]', 1, 'O operador de igualdade ''=='' é usado para comparar se os valores de duas variáveis são idênticos.', '2026-03-11T17:37:19.163889+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('be1453f9-fedd-4ccf-af3c-a8bfb3a1cc37', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Qual a finalidade da estrutura condicional ''if'' em programação?', '["Executar um bloco de c\u00f3digo repetidamente.", "Executar um bloco de c\u00f3digo se uma determinada condi\u00e7\u00e3o for verdadeira.", "Definir uma vari\u00e1vel com um valor inicial.", "Chamar uma fun\u00e7\u00e3o externa ao programa."]', 1, 'A estrutura ''if'' permite que o programa tome decisões, executando um conjunto de instruções apenas quando a condição especificada for atendida.', '2026-03-11T17:37:26.092031+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0471aba8-d4da-4c35-8722-39614d299600', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Em que situação a estrutura ''else if'' é mais aplicável?', '["Quando se deseja executar um bloco de c\u00f3digo independentemente de qualquer condi\u00e7\u00e3o.", "Quando se precisa verificar m\u00faltiplas condi\u00e7\u00f5es consecutivas e executar um bloco de c\u00f3digo espec\u00edfico para a primeira condi\u00e7\u00e3o verdadeira encontrada.", "Quando se deseja quebrar um loop de itera\u00e7\u00e3o.", "Para retornar um valor de uma fun\u00e7\u00e3o."]', 1, '''else if'' é usada para testar uma nova condição quando a condição ''if'' anterior foi falsa, permitindo cadeias de decisões.', '2026-03-11T17:37:26.092031+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6dbd09ab-2d63-4e8e-a3f2-20a5c0e4e29e', 'de4c395f-78a1-4405-b257-e38a94f8a25f', 'Se a condição em um bloco ''if'' for falsa, qual estrutura é executada (se existir)?', '["Um novo bloco ''if''.", "O bloco ''else''.", "O programa termina.", "Um loop ''for''."]', 1, 'Se a condição do ''if'' for falsa e um bloco ''else'' estiver presente, as instruções dentro do bloco ''else'' serão executadas.', '2026-03-11T17:37:26.092031+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b3518ae1-2cb7-47c7-9f95-6a85eda30bc6', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Qual é a principal finalidade da lógica computacional no desenvolvimento de software?', '["Desenvolver interfaces gr\u00e1ficas atraentes.", "Criar algoritmos eficientes para resolver problemas.", "Gerenciar bancos de dados complexos.", "Automatizar tarefas de marketing digital."]', 1, 'A lógica computacional é a base para a criação de instruções claras e sequenciais que um computador pode executar para resolver um problema.', '2026-03-11T17:37:29.363646+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4a6c3713-df77-4105-8ca7-41f00bbf6650', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'O que representa um fluxograma no contexto da lógica computacional?', '["Um c\u00f3digo escrito em linguagem de programa\u00e7\u00e3o.", "Um diagrama visual que representa o fluxo de um processo ou algoritmo.", "Um conjunto de instru\u00e7\u00f5es para o usu\u00e1rio final.", "Um documento de especifica\u00e7\u00e3o t\u00e9cnica do software."]', 1, 'Fluxogramas utilizam símbolos padronizados para ilustrar as etapas e decisões de um algoritmo, facilitando a compreensão do seu funcionamento.', '2026-03-11T17:37:29.363646+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c81d5d9f-bf2b-4935-8c77-2de709ac6dac', '942cb85a-1815-4f43-a627-0fbf477a33cf', 'Em relação ao pseudocódigo, qual das afirmações é mais precisa?', '["\u00c9 uma linguagem de programa\u00e7\u00e3o formal com sintaxe r\u00edgida.", "\u00c9 uma descri\u00e7\u00e3o textual de um algoritmo, mais pr\u00f3xima da linguagem natural.", "\u00c9 uma representa\u00e7\u00e3o gr\u00e1fica exclusiva para algoritmos complexos.", "\u00c9 utilizado apenas para a fase de testes de um programa."]', 1, 'O pseudocódigo é uma forma de descrever um algoritmo usando uma linguagem informal, mas estruturada, que se assemelha à linguagem natural, antes de ser traduzido para uma linguagem de programação real.', '2026-03-11T17:37:29.363646+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c7ecdfb7-9bbc-43ef-99f0-72d8cbfc3a08', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Qual loop é geralmente preferível quando se sabe o número exato de iterações que o código deve executar?', '["Loop ''while''.", "Loop ''for''.", "Loop ''if''.", "Loop ''else''."]', 1, 'O loop ''for'' é mais adequado quando o número de repetições é conhecido antecipadamente, pois ele gerencia o contador e a condição de parada de forma integrada.', '2026-03-11T17:37:59.439461+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1c03e742-5434-4b42-a167-d806f44e7718', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Em qual situação o loop ''while'' é mais vantajoso?', '["Quando o n\u00famero de itera\u00e7\u00f5es \u00e9 fixo e conhecido.", "Quando o loop deve continuar executando enquanto uma condi\u00e7\u00e3o espec\u00edfica for verdadeira, e o n\u00famero de itera\u00e7\u00f5es n\u00e3o \u00e9 predeterminado.", "Para executar um bloco de c\u00f3digo apenas uma vez.", "Para definir constantes no programa."]', 1, 'O loop ''while'' é ideal para situações onde a repetição depende de uma condição que pode ou não ser satisfeita em um número fixo de vezes.', '2026-03-11T17:37:59.439461+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('718a21d9-9251-4572-8ddb-37a9f94a7cf3', 'ddcfc39d-c6c6-40f3-9842-f7a2d620ca7e', 'Qual é o risco de se criar um loop sem uma condição de parada adequada?', '["O programa pode terminar prematuramente.", "O programa pode entrar em um loop infinito, travando o sistema.", "As vari\u00e1veis podem ser sobrescritas.", "Apenas uma itera\u00e7\u00e3o ser\u00e1 executada."]', 1, 'Um loop sem uma condição de parada clara ou que não é atingida fará com que o loop se execute indefinidamente, consumindo recursos e travando a aplicação.', '2026-03-11T17:37:59.439461+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a4be79d4-87a5-4871-8e96-41ff1d408a24', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'O que distingue um ''achado de auditoria'' em relação a uma simples observação?', '["Um achado \u00e9 apenas uma falha identificada.", "Um achado \u00e9 uma compara\u00e7\u00e3o documentada entre o que ''\u00e9'' e o que ''deveria ser'', com suas causas e efeitos.", "Um achado \u00e9 uma sugest\u00e3o de melhoria da gest\u00e3o.", "Um achado \u00e9 sempre uma irregularidade legal."]', 1, 'Um achado de auditoria é uma constatação completa, estruturada com base na comparação entre a situação atual observada e o critério esperado, explicando as causas dos desvios e seus efeitos.', '2026-03-12T20:32:21.14296+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c02c6503-c578-4444-951b-5dccf2d86131', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'Qual dos seguintes elementos é crucial para a formulação de uma recomendação de auditoria eficaz?', '["Ser gen\u00e9rica e aplic\u00e1vel a diversas entidades.", "Ser vaga para permitir flexibilidade na implementa\u00e7\u00e3o.", "Ser clara, objetiva, fact\u00edvel, endere\u00e7ar a causa raiz e visar \u00e0 melhoria do desempenho.", "Ser estritamente legalista, sem considerar a realidade operacional."]', 2, 'Recomendações eficazes devem ser específicas, alcançáveis, relevantes e temporizáveis, focando em resolver a causa raiz do problema e otimizar os resultados.', '2026-03-12T20:32:21.14296+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('bfe6d038-9441-4fdf-89ac-7e99120c664d', 'a4f13c4b-2dd3-4942-a323-1803383cadff', 'A estrutura de um achado de auditoria operacional geralmente inclui quais componentes?', '["Apenas a descri\u00e7\u00e3o da irregularidade.", "Condi\u00e7\u00e3o, Crit\u00e9rio, Causa e Efeito.", "Nome do auditor, data e hora da constata\u00e7\u00e3o.", "Valor do preju\u00edzo e nome do respons\u00e1vel."]', 1, 'A estrutura ''4 Cs'' – Condição (o que foi encontrado), Critério (o que deveria ser), Causa (por que aconteceu) e Efeito (consequência) – é fundamental para a elaboração de um achado completo e compreensível.', '2026-03-12T20:32:21.14296+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('109437bf-6da6-4d3d-8a5c-be5303f1cd2c', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Qual a principal característica de um relatório de auditoria operacional de alta qualidade?', '["Ser extenso e conter todos os detalhes da auditoria.", "Ser subjetivo, reflexo da opini\u00e3o do auditor.", "Ser objetivo, claro, conciso, convincente e construtivo, fornecendo informa\u00e7\u00f5es \u00fateis para a gest\u00e3o.", "Ser escrito em linguagem t\u00e9cnica e complexa para demonstrar rigor."]', 2, 'Um relatório de qualidade é aquele que comunica as informações de forma eficaz, de modo que os achados e recomendações sejam compreendidos e possam ser utilizados para aprimorar a gestão.', '2026-03-12T20:32:24.600816+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('ddb3b772-3577-4b97-b919-5ca4cfedc049', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'O que significa a fase de ''contraditório'' na auditoria operacional?', '["Confronto entre os auditores da equipe.", "Momento em que a entidade auditada tem a oportunidade de analisar os achados e recomenda\u00e7\u00f5es preliminares e apresentar sua manifesta\u00e7\u00e3o antes da finaliza\u00e7\u00e3o do relat\u00f3rio.", "Processo de revis\u00e3o do relat\u00f3rio por um auditor externo.", "Negocia\u00e7\u00e3o de prazos para a implementa\u00e7\u00e3o das recomenda\u00e7\u00f5es."]', 1, 'O contraditório é um princípio fundamental que garante o direito à defesa e a veracidade das informações, permitindo que a entidade auditada se manifeste sobre o que foi constatado, antes do relatório final.', '2026-03-12T20:32:24.600816+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('3bd74c50-4f8e-4706-9c06-823e21720045', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Qual a principal utilidade de criar uma função em um programa?', '["Para armazenar dados temporariamente.", "Para encapsular um bloco de c\u00f3digo que realiza uma tarefa espec\u00edfica e reutiliz\u00e1vel.", "Para definir a velocidade de execu\u00e7\u00e3o do programa.", "Para gerenciar a interface do usu\u00e1rio."]', 1, 'Funções permitem que você agrupe código em unidades lógicas e nomeadas que podem ser chamadas várias vezes, evitando repetição e organizando o código.', '2026-03-11T17:38:05.992607+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('fcb9925c-5409-42c4-8cea-9133bddebb5d', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'Qual a diferença entre uma função que retorna um valor e um procedimento (ou função que não retorna valor)?', '["Um procedimento \u00e9 sempre executado antes de uma fun\u00e7\u00e3o que retorna valor.", "Uma fun\u00e7\u00e3o que retorna valor produz um resultado que pode ser usado em outras partes do programa, enquanto um procedimento apenas executa a\u00e7\u00f5es sem retornar um valor expl\u00edcito.", "Um procedimento aceita par\u00e2metros, mas uma fun\u00e7\u00e3o de retorno n\u00e3o.", "N\u00e3o h\u00e1 diferen\u00e7a fundamental; s\u00e3o sin\u00f4nimos."]', 1, 'Funções que retornam valores são usadas para calcular ou obter algo que será utilizado posteriormente, enquanto procedimentos focam em realizar ''ações'' ou ''efeitos colaterais''.', '2026-03-11T17:38:05.992607+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('528d8038-96e8-4460-a20f-2498cc95084b', 'bb3d5c05-6d3c-47c2-a35f-96651bb21044', 'O que são parâmetros de uma função?', '["Os valores que a fun\u00e7\u00e3o retorna.", "Vari\u00e1veis internas que a fun\u00e7\u00e3o utiliza.", "Dados de entrada que a fun\u00e7\u00e3o recebe para processar.", "O nome da fun\u00e7\u00e3o."]', 2, 'Parâmetros são variáveis que a função aceita como entrada. Eles permitem que a função opere sobre diferentes valores a cada chamada.', '2026-03-11T17:38:05.992607+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('70fcc3cd-96a4-4d5c-a10a-c3ebca2cce2a', '48646c6a-dd4b-4fdd-9766-65d15a47b9e8', 'Qual a finalidade do monitoramento das recomendações de auditoria?', '["Determinar novas \u00e1reas para futuras auditorias.", "Verificar a implementa\u00e7\u00e3o das recomenda\u00e7\u00f5es e seus resultados, garantindo que as melhorias planejadas ocorreram.", "Reavaliar o desempenho da equipe de auditoria.", "Calcular multas e penalidades aplic\u00e1veis."]', 1, 'O monitoramento é essencial para assegurar que as ações corretivas foram tomadas e que os objetivos de melhoria foram atingidos, fechando o ciclo da auditoria e agregando valor à organização.', '2026-03-12T20:32:24.600816+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1716339a-8e5e-45c4-91f0-bd657ce71005', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'O que é um array em ciência da computação?', '["Uma estrutura para armazenar dados em formato de \u00e1rvore.", "Uma cole\u00e7\u00e3o de elementos do mesmo tipo, acessados por um \u00edndice.", "Um \u00fanico valor de dados.", "Um conjunto de fun\u00e7\u00f5es que operam em dados."]', 1, 'Um array é um tipo de estrutura de dados que armazena uma coleção de itens (geralmente do mesmo tipo) em posições sequenciais numeradas (índices).', '2026-03-11T17:38:07.075953+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('30fefcde-1656-4c41-a455-6c28420e6532', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'Como os elementos de um array são geralmente acessados?', '["Por meio de um nome \u00fanico para cada elemento.", "Pelo seu valor.", "Por um \u00edndice num\u00e9rico que representa sua posi\u00e7\u00e3o.", "Utilizando uma chave associativa."]', 2, 'Os elementos em um array são acessados através de um índice numérico, que começa em 0 para o primeiro elemento.', '2026-03-11T17:38:07.075953+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2451e47c-e778-4147-89b6-550c8dd46f2b', '53d6ae9e-98ee-4418-9a95-1ab5b835b99c', 'Qual a principal diferença entre um array de tamanho fixo e uma lista (ou array dinâmico)?', '["Arrays de tamanho fixo permitem a inser\u00e7\u00e3o de diferentes tipos de dados.", "Listas (array din\u00e2mico) podem crescer ou diminuir em tamanho durante a execu\u00e7\u00e3o do programa, enquanto arrays tradicionais t\u00eam um tamanho fixo.", "Arrays de tamanho fixo podem ser percorridos mais rapidamente.", "Listas s\u00e3o mais f\u00e1ceis de visualizar em fluxogramas."]', 1, 'Arrays tradicionais possuem um tamanho pré-definido na criação, enquanto listas são mais flexíveis e podem ser redimensionadas conforme a necessidade.', '2026-03-11T17:38:07.075953+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('cd068508-9b47-423b-a2e3-34fb31a70db9', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Por que a indentação correta do código é considerada uma boa prática?', '["Ela acelera a execu\u00e7\u00e3o do programa.", "Ela ajuda a visualizar a estrutura l\u00f3gica do c\u00f3digo, facilitando a leitura e a identifica\u00e7\u00e3o de blocos.", "Ela remove coment\u00e1rios automaticamente.", "Ela \u00e9 obrigat\u00f3ria em todas as linguagens de programa\u00e7\u00e3o."]', 1, 'A indentação alinha visualmente blocos de código (como os de ''if'', ''for'', funções), tornando a estrutura do programa mais clara e fácil de seguir.', '2026-03-11T17:38:59.721366+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4f844a87-0b9f-40af-a132-2bce58fde203', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Qual o principal objetivo de utilizar comentários no código?', '["Para enganar outros programadores.", "Para explicar a l\u00f3gica complexa ou a inten\u00e7\u00e3o por tr\u00e1s de certas partes do c\u00f3digo, auxiliando na manuten\u00e7\u00e3o e compreens\u00e3o.", "Para reduzir o tamanho do arquivo do c\u00f3digo-fonte.", "Para garantir que o c\u00f3digo seja executado mais rapidamente."]', 1, 'Comentários servem como notas explicativas para humanos, ajudando a entender o ''porquê'' e o ''como'' de partes específicas do código.', '2026-03-11T17:38:59.721366+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('0ded411a-59b0-469a-8f76-cb0e140a7ee1', 'cb939afe-ac78-4e6a-8871-b0db3ec050b2', 'Qual das seguintes convenções de nomenclatura é geralmente preferível para variáveis?', '["Nomes curtos e com uma \u00fanica letra (ex: ''a'', ''b'').", "Nomes totalmente em mai\u00fasculas (ex: ''NOMEDAVARIAVEL'').", "Nomes descritivos que refletem o prop\u00f3sito da vari\u00e1vel (ex: ''contadorDeItens'').", "Nomes com caracteres especiais e n\u00fameros no in\u00edcio."]', 2, 'Nomes descritivos e significativos para variáveis e funções facilitam enormemente a compreensão do código por você mesmo e por outros desenvolvedores.', '2026-03-11T17:38:59.721366+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('152d09ce-2706-48c3-89b5-3b6d5f84408f', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Qual a importância de aplicar os conceitos em um projeto prático?', '["Apenas para fins de avalia\u00e7\u00e3o formal.", "Para consolidar o aprendizado, identificar lacunas e desenvolver habilidades de resolu\u00e7\u00e3o de problemas reais.", "Para provar a capacidade de memoriza\u00e7\u00e3o.", "Para aprender a usar ferramentas de edi\u00e7\u00e3o de texto."]', 1, 'Projetos práticos são cruciais porque unem a teoria à prática, permitindo que os alunos enfrentem desafios reais e apliquem o conhecimento de forma integrada.', '2026-03-11T17:39:01.620666+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4302682d-0fc4-4cc7-a156-ca7f3b36d6fc', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Quais tipos de projetos simples são recomendados para iniciantes após este curso?', '["Desenvolvimento de sistemas operacionais complexos.", "Aplica\u00e7\u00f5es web b\u00e1sicas, calculadoras, jogos de adivinha\u00e7\u00e3o ou gerenciadores de tarefas simples.", "Ferramentas de intelig\u00eancia artificial avan\u00e7ada.", "Edi\u00e7\u00e3o de v\u00eddeos e anima\u00e7\u00f5es em 3D."]', 1, 'Projetos menores, como calculadoras, jogos simples ou gerenciadores de lista, permitem que os iniciantes apliquem conceitos de forma controlada e construam confiança.', '2026-03-11T17:39:01.620666+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('2520faaa-9e2c-4061-93df-01a955afbc30', '34085843-8596-43aa-a10f-20fa1a78dc7f', 'Para continuar aprendendo programação, qual das seguintes sugestões é mais valiosa?', '["Parar de codificar ap\u00f3s este curso.", "Participar de comunidades de desenvolvedores, ler documenta\u00e7\u00e3o e continuar praticando com novos desafios.", "Depender exclusivamente de tutoriais de v\u00eddeo para todas as tarefas.", "Focar apenas em teoria e nunca escrever c\u00f3digo."]', 1, 'A prática contínua, a colaboração com outros desenvolvedores e a busca ativa por conhecimento são fundamentais para o crescimento na área de programação.', '2026-03-11T17:39:01.620666+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('7e425449-a18f-41a8-a9e5-996837e1c23c', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Qual a principal característica de um algoritmo?', '["Ser amb\u00edguo e deixar margem para interpreta\u00e7\u00e3o.", "Ser executado em tempo infinito.", "Ser um conjunto finito e ordenado de instru\u00e7\u00f5es para resolver um problema.", "N\u00e3o necessitar de entrada ou sa\u00edda de dados."]', 2, 'Um algoritmo é uma sequência finita e bem definida de instruções que, ao serem executadas, produzem um resultado ou resolvem um problema específico.', '2026-03-11T17:46:59.933113+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('4abdbab7-523f-4001-b4c9-29cfe4fb08d0', '8e92b920-5447-4356-9e40-294db76d7fe6', 'O que um fluxograma representa em um algoritmo?', '["Somente o resultado final do processamento.", "A representa\u00e7\u00e3o gr\u00e1fica dos passos e decis\u00f5es do algoritmo.", "Uma lista de vari\u00e1veis utilizadas.", "O tempo de execu\u00e7\u00e3o do programa."]', 1, 'O fluxograma é uma ferramenta visual que utiliza símbolos padronizados para ilustrar o fluxo de controle e as operações de um algoritmo.', '2026-03-11T17:46:59.933113+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('db815183-d0b4-41e4-b6c7-67378782e253', '8e92b920-5447-4356-9e40-294db76d7fe6', 'Em pseudocódigo, qual é o objetivo da instrução "ENQUANTO"?', '["Executar um bloco de c\u00f3digo uma \u00fanica vez.", "Pular para uma parte espec\u00edfica do c\u00f3digo.", "Repetir um bloco de c\u00f3digo enquanto uma condi\u00e7\u00e3o for verdadeira.", "Tomar uma decis\u00e3o com base em m\u00faltiplos crit\u00e9rios."]', 2, 'A instrução "ENQUANTO" (ou WHILE em inglês) é utilizada em pseudocódigo para criar laços de repetição que continuam enquanto a condição especificada permanecer verdadeira.', '2026-03-11T17:46:59.933113+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('98171e2f-ac02-4d3a-b10a-4af2d0e72666', '511afd44-edc1-487e-bd88-d4399ec3351b', 'Qual tipo de dado é geralmente utilizado para armazenar números inteiros sem casas decimais?', '["Float", "String", "Boolean", "Integer"]', 3, 'O tipo de dado ''Integer'' é projetado especificamente para armazenar números inteiros.', '2026-03-11T17:47:00.247112+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('11223894-4644-4f5d-b26e-5d56290a7418', '511afd44-edc1-487e-bd88-d4399ec3351b', 'O que o operador de atribuição ''='' faz em programação?', '["Compara dois valores.", "Realiza uma opera\u00e7\u00e3o de adi\u00e7\u00e3o.", "Atribui um valor a uma vari\u00e1vel.", "Verifica se dois valores s\u00e3o iguais."]', 2, 'O operador ''='' é o operador de atribuição, usado para dar um valor a uma variável.', '2026-03-11T17:47:00.247112+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a6d926b7-07db-47b7-88e9-6e6c4850502f', '511afd44-edc1-487e-bd88-d4399ec3351b', 'Qual operador lógico retorna verdadeiro apenas se ambas as condições forem verdadeiras?', '["OU (OR)", "N\u00c3O (NOT)", "E (AND)", "XOR"]', 2, 'O operador lógico ''E'' (AND) retorna verdadeiro somente quando todas as condições conectadas por ele forem verdadeiras.', '2026-03-11T17:47:00.247112+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b657f1e0-9341-4202-b831-50feb0abd1a3', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Em uma estrutura condicional ''if'', qual a condição para que o bloco de código dentro dela seja executado?', '["A condi\u00e7\u00e3o deve ser falsa.", "A condi\u00e7\u00e3o deve ser verdadeira.", "N\u00e3o h\u00e1 necessidade de condi\u00e7\u00e3o.", "A condi\u00e7\u00e3o deve ser amb\u00edgua."]', 1, 'O bloco de código dentro de um ''if'' é executado somente se a condição associada a ele for avaliada como verdadeira.', '2026-03-11T17:47:00.317035+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('050df968-fb17-4ab4-81de-544a759068d2', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Qual é o propósito da cláusula ''else'' em uma estrutura ''if-else''?', '["Executar um c\u00f3digo adicional se a condi\u00e7\u00e3o principal for verdadeira.", "Executar um c\u00f3digo alternativo se a condi\u00e7\u00e3o principal for falsa.", "Encadear m\u00faltiplas condi\u00e7\u00f5es de verifica\u00e7\u00e3o.", "Definir um valor padr\u00e3o para uma vari\u00e1vel."]', 1, 'A cláusula ''else'' em uma estrutura ''if-else'' executa um bloco de código distinto quando a condição do ''if'' é falsa.', '2026-03-11T17:47:00.317035+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('1dcba15c-984d-4a72-8393-e4e15b2c94d6', '3a114a74-bcb6-4bbe-8451-33036b652eaa', 'Quando é apropriado usar a estrutura ''if-else if-else''?', '["Quando apenas uma condi\u00e7\u00e3o precisa ser verificada.", "Quando v\u00e1rias condi\u00e7\u00f5es independentes precisam ser verificadas.", "Quando precisamos de uma cadeia de verifica\u00e7\u00f5es condicionais, onde apenas um bloco de c\u00f3digo ser\u00e1 executado.", "Para declarar m\u00faltiplas vari\u00e1veis."]', 2, 'A estrutura ''if-else if-else'' é ideal para verificar uma série de condições em ordem e executar o bloco correspondente à primeira condição verdadeira encontrada.', '2026-03-11T17:47:00.317035+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('a791f8b7-5605-49d2-85fd-86387ceb0668', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Qual tipo de loop é mais adequado quando o número de iterações é conhecido antecipadamente?', '["Loop While", "Loop Do-While", "Loop For", "Loop Infinito"]', 2, 'O loop ''For'' é ideal quando se sabe exatamente quantas vezes o bloco de código precisa ser repetido, pois ele gerencia o contador e a condição de parada.', '2026-03-11T17:47:32.61753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('6261a6ce-2362-4c92-afd8-45ab12f27e87', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'Em um loop ''while'', qual é a condição para que ele continue executando?', '["A condi\u00e7\u00e3o se torna falsa.", "A condi\u00e7\u00e3o permanece verdadeira.", "Um contador atinge um valor espec\u00edfico.", "O usu\u00e1rio interage com o programa."]', 1, 'Um loop ''while'' continua executando o bloco de código enquanto a condição especificada for avaliada como verdadeira.', '2026-03-11T17:47:32.61753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('e2651b27-d370-4aad-9b5a-e2252c3ff269', '3df48214-f8a2-4188-bd9a-25f3a784fb8f', 'O que pode acontecer se a condição de parada de um loop nunca for atingida?', '["O programa finalizar\u00e1 rapidamente.", "O loop terminar\u00e1 ap\u00f3s a primeira itera\u00e7\u00e3o.", "Ocorrer\u00e1 um ''loop infinito'', travando o programa.", "O loop se transformar\u00e1 em um loop ''for''."]', 2, 'Se a condição de um loop nunca se tornar falsa (para ''while'' e ''do-while'') ou a condição de continuação nunca se tornar falsa (para ''for''), o programa entrará em um loop infinito, consumindo recursos e potencialmente travando.', '2026-03-11T17:47:32.61753+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('15f070a2-52c4-465b-8616-cad9630f6f56', 'f59c5f35-c986-4791-97ff-1681c531742a', 'O que é um array em programação?', '["Um \u00fanico valor armazenado na mem\u00f3ria.", "Uma cole\u00e7\u00e3o de elementos do mesmo tipo, acessados por um \u00edndice.", "Uma fun\u00e7\u00e3o que realiza c\u00e1lculos complexos.", "Um tipo de dado booleano."]', 1, 'Um array é uma estrutura de dados que armazena uma coleção de elementos, geralmente do mesmo tipo, em posições contíguas de memória e acessíveis por um índice numérico.', '2026-03-11T17:47:39.292077+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('c328ac79-377b-4964-a12c-cde260e70a5e', 'f59c5f35-c986-4791-97ff-1681c531742a', 'Como os índices de um array são geralmente numerados?', '["Come\u00e7ando do 1.", "Come\u00e7ando do 0.", "Aleatoriamente.", "Depende do tipo de dado."]', 1, 'Na maioria das linguagens de programação, os índices de um array começam em 0. O primeiro elemento está no índice 0, o segundo no índice 1, e assim por diante.', '2026-03-11T17:47:39.292077+00:00') ON CONFLICT DO NOTHING;
INSERT INTO "course_quiz_questions" ("id", "module_id", "question", "options", "correct_answer", "explanation", "created_at") VALUES ('b0fbcca0-0e00-4243-baf5-7c052704e4f7', 'f59c5f35-c986-4791-97ff-1681c531742a', 'Qual a principal vantagem de usar uma lista (dinâmica) em vez de um array fixo?', '["Listas s\u00e3o sempre mais r\u00e1pidas para acessar elementos.", "Listas podem crescer ou encolher dinamicamente conforme a necessidade.", "Listas garantem que todos os elementos sejam do mesmo tipo estritamente.", "Listas requerem menos mem\u00f3ria que arrays."]', 1, 'A principal vantagem das listas dinâmicas é a sua flexibilidade para adicionar ou remover elementos, ajustando automaticamente o tamanho, algo que arrays de tamanho fixo não permitem.', '2026-03-11T17:47:39.292077+00:00') ON CONFLICT DO NOTHING;
